double R = 2.0;
for (int i = 0; i &lt; 5; ++i) { // 5 vértices espaciados 72 grados
    pent_pts.push_back(R * cos(i * 2.0 * pi / 5.0));
    pent_pts.push_back(R * sin(i * 2.0 * pi / 5.0));
}
